import numpy as np

def softmax(scores: list[float]) -> list[float]:
    x = np.array(scores, dtype=np.float64)
    x -= x.max()  # numerical stability
    exp_x = np.exp(x)
    return (exp_x / exp_x.sum()).tolist()

